import{_ as e,o as a,c as t,ak as _}from"./chunks/framework.BwREiRwV.js";const m=JSON.parse('{"title":"第十三章 月光只剩一线","description":"","frontmatter":{},"headers":[],"relativePath":"永恒道途/正文/第一卷-山门有路/第十三章-月光只剩一线.md","filePath":"永恒道途/正文/第一卷-山门有路/第十三章-月光只剩一线.md"}'),r={name:"永恒道途/正文/第一卷-山门有路/第十三章-月光只剩一线.md"};function o(n,p,s,c,i,d){return a(),t("div",null,[...p[0]||(p[0]=[_('<h1 id="第十三章-月光只剩一线" tabindex="-1">第十三章 月光只剩一线 <a class="header-anchor" href="#第十三章-月光只剩一线" aria-label="Permalink to &quot;第十三章 月光只剩一线&quot;">​</a></h1><p>碎石封住洞口后，黑暗彻底压了下来。</p><p>陈玄没有立刻点火。</p><p>他侧耳贴着石壁，听了足足一刻钟。洞外只有暗河水声，偶尔夹着风吹藤叶的轻响，没有脚步，也没有兵刃碰撞。</p><p>确认追兵暂时未到，他才取出一张火绒纸，以灵力催出豆粒大小的火苗。</p><p>微光照亮山洞。</p><p>洞内比想象中更窄，最深处只有两丈，石壁布满潮湿青苔。角落散着几块小兽白骨，没有新鲜粪便，也没有蛇虫爬行痕迹。这里不是妖兽巢穴，至少今晚可以暂作藏身处。</p><p>陈玄把青锋剑放到右手能触及的位置，这才开始检查伤势。</p><p>后背从左肩到腰侧被血骨钩撕开一道长口，河水冲去大半血污，也让伤口边缘泡得发白。三根肋骨断了两根，另一根应是骨裂；右臂并未折断，只是血煞侵入经脉，暂时失去知觉。</p><p>最危险的不是这些。</p><p>一缕暗红细线正从肩后沿经脉向心口蔓延。它所过之处，皮肤先冷后热，像有烧红的针在血肉里缓慢游动。</p><p>陈玄在任务殿看过血煞伤的记载。</p><p>血魔宗功法能以他人精血为引。血煞若入心脉，伤者气血会反过来滋养煞气。届时越运功，死得越快。</p><p>留给他的时间，或许不到一夜。</p><p>陈玄从储物袋里取出那株三年回脉草。</p><p>药苗只有两指高，叶片呈淡紫色。寻常回脉草能舒缓经络、止住灵力逆冲，却无法化解血煞。至少十五年以上药龄，药性才会从“缓脉”变成“清脉”。</p><p>瓶底那滴绿液，可以做到。</p><p>但陈玄没有立刻把整滴液体倾下。</p><p>他先在洞壁下挖出一捧湿土，将回脉草根须完整埋入，再取暗河水滴在叶面。药草离土太久，根脉已有些萎缩。若直接催熟，药龄增长时根基可能先行崩断。</p><p>等叶片重新舒展，他才拔开蜡封。</p><p>掌天瓶在火光下漆黑无华。瓶身轻轻倾斜，那滴保存了近一个月的绿液缓缓移到瓶口，凝而不落。</p><p>陈玄用细竹针引出三分之一，点在根部。</p><p>翠色没入湿土。</p><p>回脉草先是轻轻一颤，根部随即传出细密声响。新须在土中迅速蔓延，茎秆拔高，淡紫叶片从三片增到七片。叶脉间一点点浮出银白细纹，清苦药香逐渐压过洞中血腥味。</p><p>十年左右。</p><p>还不够。</p><p>陈玄再引三分之一绿液。</p><p>第八片叶片抽出时，回脉草的生长明显慢了下来。根部湿土开始干裂，药香却愈发凝实，银白叶脉从叶心一路连到叶缘。</p><p>十五年。</p><p>已经达到《山药札记》记载的最低药龄。</p><p>瓶中还剩最后三分之一。</p><p>陈玄停住了。</p><p>若全部用完，药力会更强，承受不住的风险也会更大。他此刻气血衰弱、经脉受损，十五年回脉草尚且可能药性过烈，二十年药草未必是救命，反而可能先把心脉冲垮。</p><p>药不是年份越高越好。</p><p>能治病的分量，才是药。</p><p>陈玄把剩余绿液重新封回瓶底，又从回脉草上摘下最外侧两片叶。他没有整株煎服，而是先以一片混合黄精煮成药汤，另一片捣成药泥，敷在血骨钩留下的伤口两侧。</p><p>药泥触及皮肤的瞬间，一股寒意猛地钻入血肉。</p><p>陈玄身体骤然绷紧。</p><p>那不是舒缓，而是两股阴寒力量在伤口里正面相撞。回脉草药力沿经络向内渗入，血煞则像受惊毒虫般疯狂游走。原本只到肩胛的暗红细线突然向心口蹿出半寸。</p><p>陈玄立刻揭掉一半药泥。</p><p>药力稍弱后，血煞前冲速度终于慢下。他咬住布条，小口喝下药汤，以《吐纳诀》最缓的路线引导药力，先护住心脉外围三处经穴。</p><p>不能追着血煞硬逼。</p><p>他现在要做的只是守。</p><p>守到药力完全化开，守到身体重新生出一点气血，守到天亮。</p><p>第一轮药力持续了两个时辰。</p><p>陈玄浑身时冷时热，冷时牙关打颤，热时汗水从伤口里渗出。断裂肋骨随着每一次呼吸摩擦，痛得胸腔发紧。他把呼吸压得极浅，心里默数周天，不允许自己昏睡。</p><p>到后半夜，那条暗红细线终于停在心口三寸外。</p><p>陈玄没有松懈。</p><p>洞外忽然传来石子滚落声。</p><p>他立刻捻灭火苗，左手握住青锋剑。山洞重归黑暗，连药草的微光也被一件旧衣盖住。</p><p>脚步声由远及近，不止一人。</p><p>“河水到这里断了。”一个沙哑声音道，“那小子中了薛师兄的血骨钩，跑不出十里。”</p><p>“尸体兴许被冲去下游。”</p><p>“活要见人，死要见尸。少主交代过，青云宗的人若发现山寨，近期布置全得撤。”</p><p>声音隔着乱藤与碎石传入洞中，近得仿佛就在耳边。</p><p>陈玄屏住呼吸，把自身灵力尽数收回丹田。伤口仍在渗血，血腥味可能顺石缝飘出去。他摸到腰侧最后一包乌鳞草粉，若洞口被发现，只能先扬粉，再以剩下那道烟遁符冲进暗河。</p><p>可现在的身体，未必还能撑住第二次急流。</p><p>外面的人搜了很久。</p><p>一柄刀甚至从藤隙探入，在封洞碎石上敲了两下。细小石屑落到陈玄脸上，他没有眨眼，握剑的手也没有动。</p><p>“这里是实壁。”那人道。</p><p>“去下游。”</p><p>脚步终于远去。</p><p>陈玄仍等了半个时辰，直到确认对方没有折返，才慢慢松开剑柄。掌心早被冷汗浸透，胸口那道血煞也因长久屏息又向前挪了一线。</p><p>他重新点火，摘下第三片回脉草叶。</p><p>这一次，药量比先前更少。</p><p>天将亮时，暗红细线终于第一次向后退去。</p><p>只有半寸。</p><p>陈玄却知道，最危险的一关已经过去。</p><p>第二日，他仍无法站立。</p><p>洞中没有日光，只能靠月光移动与药汤次数判断时辰。陈玄把一日分成十二段，每隔一个时辰检查伤口、体温与血煞位置。回脉草一次只用半片，止血散则优先敷后背，断骨只能用布带固定，暂时不作强行复位。</p><p>饥饿时，他便吃一小片黄精和两口干粮。暗河水必须煮沸，哪怕火光可能暴露位置，也不能让腹泻拖垮身体。</p><p>第二夜，血煞退到肩井。</p><p>第三日午后，后背不再出血。陈玄用青锋剑作支撑，第一次站了起来。</p><p>脚踩实地面时，整条脊背都在颤。他只走三步便重新坐下，却没有急着再试。</p><p>身体不是敌人。它已经替他扛过血钩、暗河与血煞，强迫它立刻恢复，只会把刚接上的生机再次撕断。</p><p>第三夜，洞外又有人经过。</p><p>这次只有一人，脚步匆忙，没有停留。陈玄从石缝里看见一点火光向西北移动，空气里残留着血骨香的腥甜气味。</p><p>他把方向记在心里。</p><p>第四日，回脉草只剩三片成熟叶。血煞被逼到右臂末端，盘踞在食指与中指之间。陈玄烧红短刀，划开指尖，再以灵力从肩井向下缓慢推进。</p><p>第一滴血暗红发黑，落在石面上冒起细微腥烟。</p><p>第二滴更淡。</p><p>到第七滴时，血色终于恢复鲜红。</p><p>陈玄立刻停下，没有为了“清干净”继续压榨气血。他用止血散封住指口，靠着石壁喘了许久，才将那几滴黑血用火烧去。</p><p>血煞已除，伤势却远未痊愈。</p><p>接下来三日，他没有再服回脉草，只以黄精、干粮与吐纳恢复。药力若无病可攻，便会转而冲击经脉；那株十五年回脉草还剩根茎与三片叶，是他以后应对暗伤的底牌，不能全耗在同一处。</p><p>第七日清晨，陈玄终于能完整走完三十六周天。</p><p>灵力流过受伤经脉时仍有滞涩，却比伤前更加清晰。生死逃亡耗空了丹田，回脉草又把经络中积累一年多的细小淤伤一并清开。重新吸纳的四属灵气顺着《吐纳诀》依次归位，气旋缓慢扩张，很快触到炼气五层后期的壁障。</p><p>陈玄没有主动冲关。</p><p>他只是继续运转。</p><p>一周天，两周天，直到第四十九周天落下，那层原本因气脉淤塞而存在的阻碍自然松动。丹田气旋向内一缩，又骤然展开，灵力沿四肢百骸漫开。</p><p>炼气六层。</p><p>没有洪水般的力量，也没有伤势瞬间痊愈。</p><p>陈玄睁开眼时，断骨仍疼，后背仍不能大幅转动。新境界只是让他的灵力多了近半，气息更凝实，并没有把七日重伤从身体上抹去。</p><p>他先用半日稳住丹田，又试着出了一剑。</p><p>青元剑气离锋两尺便散，比伤前弱了许多。</p><p>这才是他此刻真实的战力。</p><p>陈玄没有失望，把剑重新归鞘。</p><p>储物袋里还剩两张引火符、一张烟遁符、半袋乌鳞草粉与三日干粮。更重要的是，洞外搜山之人已经两日没有成队出现，说明血魔宗认定他多半已死，警惕正在下降。</p><p>陈玄想起郑衡在雷光中喊出的那声“走”。若没有那张雷符逼退追兵半步，他来不及引燃烟遁符；若陆炳没有正面牵制獠熊，锁妖网也撑不到血阵出现。</p><p>三人只同行一日，谈不上深厚情义。陆炳说话强硬，郑衡也始终有所保留。可生死真正压下来时，他们没有把修为最低的陈玄推出去挡刀。</p><p>他活下来，不等于那两个人的死便只是一笔任务损耗。</p><p>若能回宗，他要把两人最后的消息带回去。</p><p>最稳妥的选择，是立刻绕路回宗。</p><p>可他手中只有对方装束与血阵的记忆，没有实物证据。任务队伍全灭，他独自返回，宗门会查，却未必能在血魔宗撤走前找到据点。</p><p>而第三夜那名落单修士离开的方向，他记得很清楚。</p><p>西北。</p><p>陈玄没有被仇恨冲昏头脑，也没打算以重伤之身闯进敌营。他要做的第一件事只是侦查：确认据点位置、人数、撤退路线；能取证便取证，不能便回宗上报。</p><p>至于杀人，是确认自己有把握之后的事。</p><p>夜幕降临，陈玄熄灭火光，把山洞里留下的药渣、血迹与灰烬全部埋入湿土。他没有带走那株回脉草，而是将其移进一处更深石缝，只摘下最后三片叶。</p><p>掌天瓶催长了它的岁月。</p><p>这座山洞给了它继续生长的地方。</p><p>瓶底剩下的三分之一滴绿液仍被蜡封着。陈玄没有因为即将侦查敌营便把它催成更多毒草。未知的危险永远比手中的准备多，保留一份尚未决定用途的资源，有时比多一件既定武器更重要。</p><p>若他还能回来，或许多年后，这里会多出一株无人知道的老药。</p><p>最后一块封洞石被移开。</p><p>陈玄在黑暗里站了片刻，等眼睛适应月色，才贴着暗河阴影向西北而去。</p><p>七日前，他是被血骨钩逼下山崖的猎物。</p><p>今夜，他仍不急着做猎人。</p><p>他只先去看清，猎人究竟藏在哪里。</p><p>（第十三章完）</p>',119)])])}const f=e(r,[["render",o]]);export{m as __pageData,f as default};
